var COURSE_PL_RU = [{day: 1, title: `Pierwsze powitania`, title_native: `Первые приветствия`, focus: `Nauczysz się podstawowych powitań i pożegnań, których użyjesz od razu po przyjeździe do Moskwy, Petersburga albo Ałmaty. Skupiamy się na prostych, uprzejmych zwrotach dla podróżnika.`, vocab: [{ru: `здравствуйте`, pl: `dzień dobry / witam`, ipa: `[ˈzdrast-vuj-tie]`},{ru: `привет`, pl: `cześć`, ipa: `[pri-viet]`},{ru: `доброе утро`, pl: `dzień dobry rano`, ipa: `[ˈdo-bra-je ˈu-tra]`},{ru: `добрый день`, pl: `dzień dobry`, ipa: `[ˈdo-bryj dien]`},{ru: `добрый вечер`, pl: `dobry wieczór`, ipa: `[ˈdo-bryj ˈvie-czier]`},{ru: `пока`, pl: `pa`, ipa: `[pa-ka]`},{ru: `до свидания`, pl: `do widzenia`, ipa: `[da svi-ˈda-ni-ja]`},{ru: `спасибо`, pl: `dziękuję`, ipa: `[spa-ˈsi-ba]`},{ru: `пожалуйста`, pl: `proszę / nie ma za co`, ipa: `[pa-ˈża-lu-sta]`},{ru: `да`, pl: `tak`, ipa: `[da]`}], phrases: [{ru: `Здравствуйте!`, pl: `Dzień dobry!`, ipa: `[ˈzdrast-vuj-tie]`},{ru: `Привет!`, pl: `Cześć!`, ipa: `[pri-viet]`},{ru: `Доброе утро!`, pl: `Dzień dobry rano!`, ipa: `[ˈdo-bra-je ˈu-tra]`},{ru: `Добрый вечер!`, pl: `Dobry wieczór!`, ipa: `[ˈdo-bryj ˈvie-czier]`},{ru: `До свидания!`, pl: `Do widzenia!`, ipa: `[da svi-ˈda-ni-ja]`},{ru: `Спасибо большое.`, pl: `Bardzo dziękuję.`, ipa: `[spa-ˈsi-ba bal-ˈszo-je]`}], grammar: `W rosyjskim często rozróżnia się styl formalny i nieformalny. Здравствуйте jest bezpieczne w hotelu, restauracji, sklepie i wobec osób starszych. Привет używaj z rówieśnikami, znajomymi albo w luźnych sytuacjach.`, practice: [`Powiedz po rosyjsku „dzień dobry” w recepcji hotelowej.`,`Powiedz po rosyjsku „cześć” do osoby w swoim wieku.`,`Połącz zwrot спасибо z polskim znaczeniem.`,`Przećwicz głośno trzy powitania: rano, w dzień i wieczorem.`,`Napisz krótką wymianę: „Dzień dobry — dziękuję — do widzenia”.`]},{day: 2, title: `Tak, nie i uprzejme reakcje`, title_native: `Да, нет и вежливые ответы`, focus: `W podróży często trzeba szybko odpowiedzieć kasjerowi, kelnerowi albo kierowcy. Dzisiaj uczysz się krótkich reakcji, które działają w większości codziennych sytuacji.`, vocab: [{ru: `нет`, pl: `nie`, ipa: `[niet]`},{ru: `хорошо`, pl: `dobrze`, ipa: `[ha-ra-ˈszo]`},{ru: `ладно`, pl: `okej / dobrze`, ipa: `[ˈład-na]`},{ru: `извините`, pl: `przepraszam`, ipa: `[iz-vi-ˈni-tie]`},{ru: `простите`, pl: `przepraszam`, ipa: `[pra-ˈsti-tie]`},{ru: `ничего`, pl: `nic się nie stało`, ipa: `[ni-czie-ˈwo]`},{ru: `конечно`, pl: `oczywiście`, ipa: `[ka-ˈniecz-na]`},{ru: `может быть`, pl: `może`, ipa: `[ˈmo-żet byt]`},{ru: `не знаю`, pl: `nie wiem`, ipa: `[nie ˈzna-ju]`},{ru: `я понимаю`, pl: `rozumiem`, ipa: `[ja pa-ni-ˈma-ju]`}], phrases: [{ru: `Да, конечно.`, pl: `Tak, oczywiście.`, ipa: `[da ka-ˈniecz-na]`},{ru: `Нет, спасибо.`, pl: `Nie, dziękuję.`, ipa: `[niet spa-ˈsi-ba]`},{ru: `Хорошо, спасибо.`, pl: `Dobrze, dziękuję.`, ipa: `[ha-ra-ˈszo spa-ˈsi-ba]`},{ru: `Извините, пожалуйста.`, pl: `Przepraszam, proszę.`, ipa: `[iz-vi-ˈni-tie pa-ˈża-lu-sta]`},{ru: `Я не знаю.`, pl: `Nie wiem.`, ipa: `[ja nie ˈzna-ju]`},{ru: `Я понимаю.`, pl: `Rozumiem.`, ipa: `[ja pa-ni-ˈma-ju]`}], grammar: `Я oznacza „ja”, a не przed czasownikiem tworzy zaprzeczenie. Я знаю to „wiem”, a я не знаю to „nie wiem”. W praktyce podróżnej krótka odpowiedź Нет, спасибо jest bardzo przydatna, gdy ktoś coś proponuje.`, practice: [`Odpowiedz po rosyjsku „nie, dziękuję” sprzedawcy.`,`Powiedz „tak, oczywiście” w formalnej sytuacji.`,`Przećwicz różnicę między знаю i не знаю.`,`Ułóż zdanie z извините.`,`Powiedz po rosyjsku: „Dobrze, rozumiem”.`]},{day: 3, title: `Przedstawianie się`, title_native: `Знакомство`, focus: `Nauczysz się mówić, jak masz na imię, skąd jesteś i że jesteś z Polski. Przyda się to w hostelu, na wycieczce, w pociągu albo podczas luźnej rozmowy w kawiarni.`, vocab: [{ru: `меня зовут`, pl: `mam na imię`, ipa: `[mi-ˈnia za-ˈwut]`},{ru: `имя`, pl: `imię`, ipa: `[ˈi-mia]`},{ru: `я`, pl: `ja`, ipa: `[ja]`},{ru: `вы`, pl: `pan / pani / wy`, ipa: `[wy]`},{ru: `ты`, pl: `ty`, ipa: `[ty]`},{ru: `Польша`, pl: `Polska`, ipa: `[ˈpol-sza]`},{ru: `поляк`, pl: `Polak`, ipa: `[pa-ˈliak]`},{ru: `полька`, pl: `Polka`, ipa: `[ˈpol-ka]`},{ru: `турист`, pl: `turysta`, ipa: `[tu-ˈrist]`},{ru: `приятно`, pl: `miło`, ipa: `[pri-ˈjat-na]`}], phrases: [{ru: `Меня зовут Анна.`, pl: `Mam na imię Anna.`, ipa: `[mi-ˈnia za-ˈwut ˈan-na]`},{ru: `Я из Польши.`, pl: `Jestem z Polski.`, ipa: `[ja iz ˈpol-szy]`},{ru: `Я турист.`, pl: `Jestem turystą.`, ipa: `[ja tu-ˈrist]`},{ru: `Очень приятно.`, pl: `Bardzo mi miło.`, ipa: `[ˈo-czeń pri-ˈjat-na]`},{ru: `Как вас зовут?`, pl: `Jak się pan/pani nazywa?`, ipa: `[kak was za-ˈwut]`},{ru: `Как тебя зовут?`, pl: `Jak masz na imię?`, ipa: `[kak ti-ˈbia za-ˈwut]`}], grammar: `Po rosyjsku często mówi się dosłownie „mnie nazywają” zamiast „ja mam na imię”: Меня зовут. W formalnej sytuacji pytaj Как вас зовут?, a w luźnej Как тебя зовут?. Różnica między вы i ты jest podobna do polskiego „pan/pani” i „ty”.`, practice: [`Przedstaw się po rosyjsku swoim imieniem.`,`Powiedz, że jesteś z Polski.`,`Zapytaj formalnie recepcjonistę, jak się nazywa.`,`Zapytaj nieformalnie nowego znajomego o imię.`,`Ułóż krótką rozmowę: imię, kraj, „miło mi”.`]},{day: 4, title: `Liczby od 0 do 20`, title_native: `Числа от 0 до 20`, focus: `Liczby są potrzebne przy płaceniu, kupowaniu biletów i podawaniu numeru pokoju. Dzisiaj ćwiczysz podstawowy zakres, który usłyszysz w sklepie i transporcie.`, vocab: [{ru: `ноль`, pl: `zero`, ipa: `[nol]`},{ru: `один`, pl: `jeden`, ipa: `[a-ˈdin]`},{ru: `два`, pl: `dwa`, ipa: `[dwa]`},{ru: `три`, pl: `trzy`, ipa: `[tri]`},{ru: `четыре`, pl: `cztery`, ipa: `[czie-ˈty-rie]`},{ru: `пять`, pl: `pięć`, ipa: `[piat]`},{ru: `шесть`, pl: `sześć`, ipa: `[szest]`},{ru: `семь`, pl: `siedem`, ipa: `[siem]`},{ru: `восемь`, pl: `osiem`, ipa: `[ˈwo-siem]`},{ru: `десять`, pl: `dziesięć`, ipa: `[ˈdie-siat]`}], phrases: [{ru: `Один билет, пожалуйста.`, pl: `Jeden bilet, proszę.`, ipa: `[a-ˈdin bi-ˈliet pa-ˈża-lu-sta]`},{ru: `Два кофе, пожалуйста.`, pl: `Dwie kawy, proszę.`, ipa: `[dwa ˈko-fie pa-ˈża-lu-sta]`},{ru: `Три билета.`, pl: `Trzy bilety.`, ipa: `[tri bi-ˈlie-ta]`},{ru: `Номер пять.`, pl: `Numer pięć.`, ipa: `[ˈno-mier piat]`},{ru: `Сколько стоит?`, pl: `Ile kosztuje?`, ipa: `[ˈskol-ka ˈsto-it]`},{ru: `Это десять рублей.`, pl: `To dziesięć rubli.`, ipa: `[ˈe-ta ˈdie-siat rub-ˈliej]`}], grammar: `Rzeczowniki po liczbach w rosyjskim potrafią zmieniać formę, ale na początku najważniejsze jest, by liczba była zrozumiała. W podróży często wystarczy powiedzieć Один билет albo Два кофе. Zwracaj uwagę na akcent, bo он w один pada na drugą sylabę.`, practice: [`Policz po rosyjsku od 0 do 10.`,`Zamów jeden bilet po rosyjsku.`,`Zamów dwie kawy po rosyjsku.`,`Powiedz „numer pięć”.`,`Zapytaj „ile kosztuje?”.`]},{day: 5, title: `Dni, godziny i proste planowanie`, title_native: `Дни, время и простые планы`, focus: `W Kazaniu, Mińsku czy Petersburgu możesz potrzebować zapytać o godzinę odjazdu lub dzień rezerwacji. Dzisiaj uczysz się podstaw czasu i planowania.`, vocab: [{ru: `сегодня`, pl: `dzisiaj`, ipa: `[sie-ˈwo-dnia]`},{ru: `завтра`, pl: `jutro`, ipa: `[ˈzaw-tra]`},{ru: `вчера`, pl: `wczoraj`, ipa: `[f-czie-ˈra]`},{ru: `утро`, pl: `rano`, ipa: `[ˈu-tra]`},{ru: `день`, pl: `dzień`, ipa: `[dien]`},{ru: `вечер`, pl: `wieczór`, ipa: `[ˈvie-czier]`},{ru: `ночь`, pl: `noc`, ipa: `[nocz]`},{ru: `час`, pl: `godzina`, ipa: `[czas]`},{ru: `минута`, pl: `minuta`, ipa: `[mi-ˈnu-ta]`},{ru: `сейчас`, pl: `teraz`, ipa: `[siej-ˈczas]`}], phrases: [{ru: `Который час?`, pl: `Która godzina?`, ipa: `[ka-ˈto-ryj czas]`},{ru: `Сейчас два часа.`, pl: `Teraz jest druga.`, ipa: `[siej-ˈczas dwa cza-ˈsa]`},{ru: `Сегодня вечером.`, pl: `Dzisiaj wieczorem.`, ipa: `[sie-ˈwo-dnia ˈvie-czie-ram]`},{ru: `Завтра утром.`, pl: `Jutro rano.`, ipa: `[ˈzaw-tra ˈu-tram]`},{ru: `Когда поезд?`, pl: `Kiedy jest pociąg?`, ipa: `[kag-ˈda ˈpo-jizd]`},{ru: `В восемь часов.`, pl: `O ósmej.`, ipa: `[w ˈwo-siem cza-ˈsow]`}], grammar: `Когда oznacza „kiedy” i jest jednym z najważniejszych pytań podróżnych. Сколько pyta o ilość lub cenę, a который час pyta o godzinę. W rosyjskim często pomija się czasownik „jest”, więc Сейчас два часа dosłownie znaczy „teraz dwie godziny”.`, practice: [`Zapytaj po rosyjsku, która jest godzina.`,`Powiedz „jutro rano”.`,`Powiedz „dzisiaj wieczorem”.`,`Zapytaj, kiedy jest pociąg.`,`Ułóż krótką odpowiedź: „O ósmej”.`]},{day: 6, title: `Na lotnisku`, title_native: `В аэропорту`, focus: `Dzisiaj ćwiczysz słowa i zwroty potrzebne po przylocie do rosyjskojęzycznego miasta. Nauczysz się pytać o bagaż, paszport, kontrolę i wyjście.`, vocab: [{ru: `аэропорт`, pl: `lotnisko`, ipa: `[a-e-ra-ˈport]`},{ru: `паспорт`, pl: `paszport`, ipa: `[ˈpas-part]`},{ru: `багаж`, pl: `bagaż`, ipa: `[ba-ˈgaż]`},{ru: `чемодан`, pl: `walizka`, ipa: `[czie-ma-ˈdan]`},{ru: `рейс`, pl: `lot`, ipa: `[riejs]`},{ru: `выход`, pl: `wyjście`, ipa: `[ˈwy-hat]`},{ru: `контроль`, pl: `kontrola`, ipa: `[kan-ˈtrol]`},{ru: `таможня`, pl: `cło`, ipa: `[ta-ˈmoż-nia]`},{ru: `прилет`, pl: `przylot`, ipa: `[pri-ˈliot]`},{ru: `такси`, pl: `taksówka`, ipa: `[tak-ˈsi]`}], phrases: [{ru: `Где багаж?`, pl: `Gdzie jest bagaż?`, ipa: `[gdie ba-ˈgaż]`},{ru: `Вот мой паспорт.`, pl: `Oto mój paszport.`, ipa: `[wot moj ˈpas-part]`},{ru: `Где выход?`, pl: `Gdzie jest wyjście?`, ipa: `[gdie ˈwy-hat]`},{ru: `Мне нужно такси.`, pl: `Potrzebuję taksówki.`, ipa: `[mnie ˈnuż-na tak-ˈsi]`},{ru: `Это мой чемодан.`, pl: `To moja walizka.`, ipa: `[ˈe-ta moj czie-ma-ˈdan]`},{ru: `Где паспортный контроль?`, pl: `Gdzie jest kontrola paszportowa?`, ipa: `[gdie ˈpas-part-nyj kan-ˈtrol]`}], grammar: `Где oznacza „gdzie” i jest bardzo praktyczne: Где выход?, Где багаж?, Где такси?. Zwrot мне нужно znaczy „potrzebuję” albo „jest mi potrzebne”. Możesz go używać bez odmiany czasownika, co jest wygodne dla początkującego.`, practice: [`Zapytaj, gdzie jest wyjście.`,`Powiedz „oto mój paszport”.`,`Zapytaj, gdzie jest bagaż.`,`Powiedz, że potrzebujesz taksówki.`,`Ułóż trzy pytania zaczynające się od Где.`]},{day: 7, title: `Hotel i zameldowanie`, title_native: `Отель и регистрация`, focus: `W hotelu w Petersburgu lub Mińsku musisz podać nazwisko, potwierdzić rezerwację i zapytać o pokój. Dzisiaj ćwiczysz spokojne, formalne zwroty recepcyjne.`, vocab: [{ru: `отель`, pl: `hotel`, ipa: `[a-ˈtiel]`},{ru: `гостиница`, pl: `hotel`, ipa: `[ga-ˈsti-ni-ca]`},{ru: `номер`, pl: `pokój / numer`, ipa: `[ˈno-mier]`},{ru: `ключ`, pl: `klucz`, ipa: `[klucz]`},{ru: `бронь`, pl: `rezerwacja`, ipa: `[bron]`},{ru: `регистрация`, pl: `rejestracja / zameldowanie`, ipa: `[rie-gi-stra-ˈcy-ja]`},{ru: `фамилия`, pl: `nazwisko`, ipa: `[fa-ˈmi-li-ja]`},{ru: `паспорт`, pl: `paszport`, ipa: `[ˈpas-part]`},{ru: `лифт`, pl: `winda`, ipa: `[lift]`},{ru: `завтрак`, pl: `śniadanie`, ipa: `[ˈzaw-trak]`}], phrases: [{ru: `У меня есть бронь.`, pl: `Mam rezerwację.`, ipa: `[u mi-ˈnia jest bron]`},{ru: `На фамилию Ковальский.`, pl: `Na nazwisko Kowalski.`, ipa: `[na fa-ˈmi-li-ju ka-ˈwal-ski]`},{ru: `Вот мой паспорт.`, pl: `Oto mój paszport.`, ipa: `[wot moj ˈpas-part]`},{ru: `Где мой номер?`, pl: `Gdzie jest mój pokój?`, ipa: `[gdie moj ˈno-mier]`},{ru: `Где лифт?`, pl: `Gdzie jest winda?`, ipa: `[gdie lift]`},{ru: `Завтрак включён?`, pl: `Czy śniadanie jest wliczone?`, ipa: `[ˈzaw-trak wklu-ˈczon]`}], grammar: `У меня есть oznacza „mam” w sensie posiadania czegoś. Dosłownie to konstrukcja „u mnie jest”, ale w praktyce używasz jej jak polskiego „mam”. У меня есть бронь to jedno z najważniejszych zdań w hotelu.`, practice: [`Powiedz recepcjoniście, że masz rezerwację.`,`Podaj nazwisko po rosyjsku, używając На фамилию.`,`Zapytaj, gdzie jest winda.`,`Zapytaj, czy śniadanie jest wliczone.`,`Ułóż mini-dialog zameldowania w hotelu.`]},{day: 8, title: `Kierunki i orientacja w mieście`, title_native: `Направления и город`, focus: `Podczas spaceru po centrum Moskwy lub Ałmaty możesz zgubić drogę albo zapytać o metro. Dzisiaj uczysz się kierunków i prostych instrukcji.`, vocab: [{ru: `город`, pl: `miasto`, ipa: `[ˈgo-rat]`},{ru: `улица`, pl: `ulica`, ipa: `[ˈu-li-ca]`},{ru: `площадь`, pl: `plac`, ipa: `[ˈplo-szczat]`},{ru: `метро`, pl: `metro`, ipa: `[mie-ˈtro]`},{ru: `слева`, pl: `po lewej`, ipa: `[ˈslie-wa]`},{ru: `справа`, pl: `po prawej`, ipa: `[ˈspra-wa]`},{ru: `прямо`, pl: `prosto`, ipa: `[ˈpria-ma]`},{ru: `назад`, pl: `z powrotem / do tyłu`, ipa: `[na-ˈzat]`},{ru: `рядом`, pl: `obok / niedaleko`, ipa: `[ˈria-dam]`},{ru: `далеко`, pl: `daleko`, ipa: `[da-li-ˈko]`}], phrases: [{ru: `Где метро?`, pl: `Gdzie jest metro?`, ipa: `[gdie mie-ˈtro]`},{ru: `Идите прямо.`, pl: `Proszę iść prosto.`, ipa: `[i-ˈdi-tie ˈpria-ma]`},{ru: `Поверните налево.`, pl: `Proszę skręcić w lewo.`, ipa: `[pa-wier-ˈni-tie na-ˈlie-wa]`},{ru: `Поверните направо.`, pl: `Proszę skręcić w prawo.`, ipa: `[pa-wier-ˈni-tie na-ˈpra-wa]`},{ru: `Это далеко?`, pl: `Czy to daleko?`, ipa: `[ˈe-ta da-li-ˈko]`},{ru: `Это рядом.`, pl: `To blisko.`, ipa: `[ˈe-ta ˈria-dam]`}], grammar: `Rosyjskie polecenia grzeczne często kończą się na -те: идите, поверните, скажите. To forma formalna lub uprzejma, bardzo przydatna w kontaktach z nieznajomymi. Gdy ktoś mówi Идите прямо, oznacza to „proszę iść prosto”.`, practice: [`Zapytaj, gdzie jest metro.`,`Powiedz komuś, by poszedł prosto.`,`Przećwicz „w lewo” i „w prawo”.`,`Zapytaj, czy to daleko.`,`Narysuj prostą mapkę i opisz trasę po rosyjsku.`]},{day: 9, title: `Transport publiczny`, title_native: `Общественный транспорт`, focus: `Dzisiaj ćwiczysz słownictwo związane z metrem, autobusem, tramwajem i biletami. Przyda się to w dużych miastach, gdzie transport publiczny jest szybki, ale bywa intensywny.`, vocab: [{ru: `автобус`, pl: `autobus`, ipa: `[af-ˈto-bus]`},{ru: `трамвай`, pl: `tramwaj`, ipa: `[tram-ˈwaj]`},{ru: `троллейбус`, pl: `trolejbus`, ipa: `[tra-ˈliej-bus]`},{ru: `поезд`, pl: `pociąg`, ipa: `[ˈpo-jizd]`},{ru: `станция`, pl: `stacja`, ipa: `[ˈstan-cy-ja]`},{ru: `остановка`, pl: `przystanek`, ipa: `[a-sta-ˈnof-ka]`},{ru: `билет`, pl: `bilet`, ipa: `[bi-ˈliet]`},{ru: `карта`, pl: `karta`, ipa: `[ˈkar-ta]`},{ru: `пересадка`, pl: `przesiadka`, ipa: `[pie-rie-ˈsat-ka]`},{ru: `маршрут`, pl: `trasa`, ipa: `[mar-ˈszrut]`}], phrases: [{ru: `Один билет, пожалуйста.`, pl: `Jeden bilet, proszę.`, ipa: `[a-ˈdin bi-ˈliet pa-ˈża-lu-sta]`},{ru: `Где остановка автобуса?`, pl: `Gdzie jest przystanek autobusowy?`, ipa: `[gdie a-sta-ˈnof-ka af-ˈto-bu-sa]`},{ru: `Какая станция?`, pl: `Jaka stacja?`, ipa: `[ka-ˈka-ja ˈstan-cy-ja]`},{ru: `Мне нужна карта метро.`, pl: `Potrzebuję mapy metra.`, ipa: `[mnie ˈnuż-na ˈkar-ta mie-ˈtro]`},{ru: `Это мой поезд?`, pl: `Czy to mój pociąg?`, ipa: `[ˈe-ta moj ˈpo-jizd]`},{ru: `Нужна пересадка?`, pl: `Czy potrzebna jest przesiadka?`, ipa: `[ˈnuż-na pie-rie-ˈsat-ka]`}], grammar: `Мне нужна znaczy „potrzebuję” dla rzeczowników rodzaju żeńskiego, jak карта. Dla rodzaju męskiego usłyszysz мне нужен, a dla nijakiego мне нужно. Na początku zapamiętaj całe zwroty: Мне нужна карта i Мне нужно такси.`, practice: [`Kup jeden bilet po rosyjsku.`,`Zapytaj, gdzie jest przystanek autobusu.`,`Zapytaj, czy potrzebna jest przesiadka.`,`Powiedz, że potrzebujesz mapy metra.`,`Ułóż trzy zdania z транспортными słowami: метро, автобус, поезд.`]},{day: 10, title: `Taksówka i przejazd`, title_native: `Такси и поездка`, focus: `W podróży możesz zamówić taksówkę z lotniska, hotelu lub restauracji. Dzisiaj uczysz się mówić adres, pytać o cenę i wyjaśniać, dokąd chcesz jechać.`, vocab: [{ru: `такси`, pl: `taksówka`, ipa: `[tak-ˈsi]`},{ru: `водитель`, pl: `kierowca`, ipa: `[wa-ˈdi-tiel]`},{ru: `адрес`, pl: `adres`, ipa: `[a-ˈdries]`},{ru: `центр`, pl: `centrum`, ipa: `[centr]`},{ru: `вокзал`, pl: `dworzec`, ipa: `[vag-ˈzał]`},{ru: `аэропорт`, pl: `lotnisko`, ipa: `[a-e-ra-ˈport]`},{ru: `отель`, pl: `hotel`, ipa: `[a-ˈtiel]`},{ru: `поездка`, pl: `przejazd`, ipa: `[pa-ˈjest-ka]`},{ru: `дорога`, pl: `droga`, ipa: `[da-ˈro-ga]`},{ru: `цена`, pl: `cena`, ipa: `[cie-ˈna]`}], phrases: [{ru: `Мне нужно в центр.`, pl: `Muszę do centrum.`, ipa: `[mnie ˈnuż-na f centr]`},{ru: `Мне нужно в аэропорт.`, pl: `Muszę na lotnisko.`, ipa: `[mnie ˈnuż-na v a-e-ra-ˈport]`},{ru: `Сколько стоит поездка?`, pl: `Ile kosztuje przejazd?`, ipa: `[ˈskol-ka ˈsto-it pa-ˈjest-ka]`},{ru: `Вот адрес.`, pl: `Oto adres.`, ipa: `[wot a-ˈdries]`},{ru: `Можно картой?`, pl: `Czy można kartą?`, ipa: `[ˈmoż-na ˈkar-taj]`},{ru: `Остановите здесь, пожалуйста.`, pl: `Proszę zatrzymać się tutaj.`, ipa: `[a-sta-na-ˈwi-tie zdieś pa-ˈża-lu-sta]`}], grammar: `В może oznaczać „do” albo „w”, zależnie od kontekstu. Мне нужно в центр znaczy „muszę do centrum”. W mowie potocznej to szybki i naturalny sposób powiedzenia kierowcy, dokąd jedziesz.`, practice: [`Powiedz kierowcy, że musisz do centrum.`,`Zapytaj o koszt przejazdu.`,`Powiedz „oto adres”.`,`Zapytaj, czy można zapłacić kartą.`,`Poproś kierowcę, by zatrzymał się tutaj.`]},{day: 11, title: `Kawiarnia i proste zamówienie`, title_native: `Кафе и простой заказ`, focus: `Dzisiaj zamawiasz kawę, herbatę i coś słodkiego w kawiarni. Uczysz się mówić „poproszę”, „na miejscu”, „na wynos” i pytać o cenę.`, vocab: [{ru: `кафе`, pl: `kawiarnia`, ipa: `[ka-ˈfie]`},{ru: `кофе`, pl: `kawa`, ipa: `[ˈko-fie]`},{ru: `чай`, pl: `herbata`, ipa: `[czaj]`},{ru: `вода`, pl: `woda`, ipa: `[wa-ˈda]`},{ru: `молоко`, pl: `mleko`, ipa: `[ma-la-ˈko]`},{ru: `сахар`, pl: `cukier`, ipa: `[ˈsa-har]`},{ru: `пирог`, pl: `ciasto / placek`, ipa: `[pi-ˈrok]`},{ru: `булочка`, pl: `bułeczka`, ipa: `[ˈbu-lacz-ka]`},{ru: `чек`, pl: `paragon / rachunek`, ipa: `[czek]`},{ru: `заказ`, pl: `zamówienie`, ipa: `[za-ˈkas]`}], phrases: [{ru: `Кофе, пожалуйста.`, pl: `Kawę, proszę.`, ipa: `[ˈko-fie pa-ˈża-lu-sta]`},{ru: `Чай с лимоном, пожалуйста.`, pl: `Herbatę z cytryną, proszę.`, ipa: `[czaj s li-ˈmo-nam pa-ˈża-lu-sta]`},{ru: `Можно без сахара?`, pl: `Czy można bez cukru?`, ipa: `[ˈmoż-na biez ˈsa-ha-ra]`},{ru: `Мне воду, пожалуйста.`, pl: `Wodę dla mnie, proszę.`, ipa: `[mnie ˈwo-du pa-ˈża-lu-sta]`},{ru: `На месте или с собой?`, pl: `Na miejscu czy na wynos?`, ipa: `[na ˈmie-stie ˈi-li s sa-ˈboj]`},{ru: `С собой, пожалуйста.`, pl: `Na wynos, proszę.`, ipa: `[s sa-ˈboj pa-ˈża-lu-sta]`}], grammar: `С oznacza „z”, a без oznacza „bez”. Чай с лимоном to herbata z cytryną, a кофе без сахара to kawa bez cukru. W kawiarni możesz mówić krótko: Кофе, пожалуйста — to brzmi naturalnie.`, practice: [`Zamów kawę po rosyjsku.`,`Zamów herbatę z cytryną.`,`Poproś o napój bez cukru.`,`Powiedz, że chcesz na wynos.`,`Odegraj scenkę przy kasie w kawiarni.`]},{day: 12, title: `Restauracja i menu`, title_native: `Ресторан и меню`, focus: `W restauracji nauczysz się poprosić o menu, zamówić danie i poprosić o rachunek. Ćwiczymy zdania, które są krótkie, uprzejme i praktyczne.`, vocab: [{ru: `ресторан`, pl: `restauracja`, ipa: `[ries-ta-ˈran]`},{ru: `меню`, pl: `menu`, ipa: `[mie-ˈniu]`},{ru: `суп`, pl: `zupa`, ipa: `[sup]`},{ru: `салат`, pl: `sałatka`, ipa: `[sa-ˈłat]`},{ru: `рыба`, pl: `ryba`, ipa: `[ˈry-ba]`},{ru: `мясо`, pl: `mięso`, ipa: `[ˈmia-sa]`},{ru: `курица`, pl: `kurczak`, ipa: `[ˈku-ri-ca]`},{ru: `картошка`, pl: `ziemniaki`, ipa: `[kar-ˈtosz-ka]`},{ru: `хлеб`, pl: `chleb`, ipa: `[chlieb]`},{ru: `счёт`, pl: `rachunek`, ipa: `[szczot]`}], phrases: [{ru: `Меню, пожалуйста.`, pl: `Menu, proszę.`, ipa: `[mie-ˈniu pa-ˈża-lu-sta]`},{ru: `Что вы рекомендуете?`, pl: `Co pan/pani poleca?`, ipa: `[szto wy rie-ka-mien-ˈdu-je-tie]`},{ru: `Я возьму суп.`, pl: `Wezmę zupę.`, ipa: `[ja waz-ˈmu sup]`},{ru: `Без мяса, пожалуйста.`, pl: `Bez mięsa, proszę.`, ipa: `[biez ˈmia-sa pa-ˈża-lu-sta]`},{ru: `Счёт, пожалуйста.`, pl: `Rachunek, proszę.`, ipa: `[szczot pa-ˈża-lu-sta]`},{ru: `Очень вкусно.`, pl: `Bardzo smaczne.`, ipa: `[ˈo-czeń ˈfkus-na]`}], grammar: `Я возьму oznacza „wezmę” i jest bardzo naturalne przy zamawianiu. Możesz powiedzieć Я возьму суп, Я возьму салат albo Я возьму кофе. To prosty wzór, który działa w restauracji i kawiarni.`, practice: [`Poproś o menu.`,`Zapytaj kelnera, co poleca.`,`Zamów zupę.`,`Powiedz „bez mięsa, proszę”.`,`Poproś o rachunek.`]},{day: 13, title: `Jedzenie, preferencje i alergie`, title_native: `Еда, предпочтения и аллергии`, focus: `Dzisiaj nauczysz się mówić, czego nie jesz, co lubisz i na co masz alergię. To ważne przy zamawianiu jedzenia w obcym kraju.`, vocab: [{ru: `еда`, pl: `jedzenie`, ipa: `[je-ˈda]`},{ru: `аллергия`, pl: `alergia`, ipa: `[a-lier-ˈgi-ja]`},{ru: `орехи`, pl: `orzechy`, ipa: `[a-ˈrie-hi]`},{ru: `молочные продукты`, pl: `produkty mleczne`, ipa: `[ˈmo-lacz-ny-je pra-ˈduk-ty]`},{ru: `яйцо`, pl: `jajko`, ipa: `[jaj-ˈco]`},{ru: `острый`, pl: `ostry`, ipa: `[ˈos-tryj]`},{ru: `сладкий`, pl: `słodki`, ipa: `[ˈsłat-kij]`},{ru: `солёный`, pl: `słony`, ipa: `[sa-ˈlio-nyj]`},{ru: `вегетарианский`, pl: `wegetariański`, ipa: `[wie-gie-ta-ri-ˈan-skij]`},{ru: `безопасно`, pl: `bezpiecznie`, ipa: `[bie-za-ˈpas-na]`}], phrases: [{ru: `У меня аллергия на орехи.`, pl: `Mam alergię na orzechy.`, ipa: `[u mi-ˈnia a-lier-ˈgi-ja na a-ˈrie-hi]`},{ru: `Я не ем мясо.`, pl: `Nie jem mięsa.`, ipa: `[ja nie jem ˈmia-sa]`},{ru: `Это острое?`, pl: `Czy to jest ostre?`, ipa: `[ˈe-ta ˈos-tra-je]`},{ru: `Это сладкое?`, pl: `Czy to jest słodkie?`, ipa: `[ˈe-ta ˈsłat-ka-je]`},{ru: `Есть вегетарианское блюдо?`, pl: `Czy jest danie wegetariańskie?`, ipa: `[jest wie-gie-ta-ri-ˈan-ska-je ˈbliu-da]`},{ru: `Мне нельзя молоко.`, pl: `Nie mogę mleka.`, ipa: `[mnie nie-ˈlzia ma-la-ˈko]`}], grammar: `У меня аллергия на... oznacza „mam alergię na...”. Po на podajesz składnik, np. орехи albo молоко. Gdy mówisz Мне нельзя..., przekazujesz, że czegoś nie wolno ci jeść lub pić ze względów zdrowotnych.`, practice: [`Powiedz, że masz alergię na orzechy.`,`Powiedz, że nie jesz mięsa.`,`Zapytaj, czy danie jest ostre.`,`Zapytaj o danie wegetariańskie.`,`Ułóż krótką notatkę dla kelnera o swojej diecie.`]},{day: 14, title: `Zakupy spożywcze`, title_native: `Покупка продуктов`, focus: `Na targu albo w małym sklepie nauczysz się prosić o wodę, owoce, chleb i podawać ilość. To praktyczny dzień dla osób, które lubią zwiedzać lokalnie.`, vocab: [{ru: `магазин`, pl: `sklep`, ipa: `[ma-ga-ˈzin]`},{ru: `рынок`, pl: `targ`, ipa: `[ˈry-nak]`},{ru: `хлеб`, pl: `chleb`, ipa: `[chlieb]`},{ru: `сыр`, pl: `ser`, ipa: `[syr]`},{ru: `яблоко`, pl: `jabłko`, ipa: `[ˈjab-la-ka]`},{ru: `банан`, pl: `banan`, ipa: `[ba-ˈnan]`},{ru: `вода`, pl: `woda`, ipa: `[wa-ˈda]`},{ru: `сок`, pl: `sok`, ipa: `[sok]`},{ru: `килограмм`, pl: `kilogram`, ipa: `[ki-la-ˈgram]`},{ru: `пакет`, pl: `torba / reklamówka`, ipa: `[pa-ˈkiet]`}], phrases: [{ru: `Мне хлеб, пожалуйста.`, pl: `Chleb dla mnie, proszę.`, ipa: `[mnie chlieb pa-ˈża-lu-sta]`},{ru: `Один килограмм яблок.`, pl: `Kilogram jabłek.`, ipa: `[a-ˈdin ki-la-ˈgram ˈjab-lak]`},{ru: `Бутылку воды, пожалуйста.`, pl: `Butelkę wody, proszę.`, ipa: `[bu-ˈtył-ku wa-ˈdy pa-ˈża-lu-sta]`},{ru: `Сколько это стоит?`, pl: `Ile to kosztuje?`, ipa: `[ˈskol-ka ˈe-ta ˈsto-it]`},{ru: `Пакет нужен?`, pl: `Czy potrzebna torba?`, ipa: `[pa-ˈkiet ˈnu-żen]`},{ru: `Да, пакет, пожалуйста.`, pl: `Tak, torbę proszę.`, ipa: `[da pa-ˈkiet pa-ˈża-lu-sta]`}], grammar: `W sklepie często usłyszysz Нужен пакет? czyli „czy potrzebna torba?”. Нужен używa się z rzeczownikami rodzaju męskiego, jak пакет. Odpowiedź może być bardzo prosta: Да, пожалуйста albo Нет, спасибо.`, practice: [`Poproś o chleb.`,`Kup butelkę wody.`,`Zapytaj, ile coś kosztuje.`,`Odpowiedz, że potrzebujesz torby.`,`Odegraj krótką scenę na targu.`]},{day: 15, title: `Pieniądze i płatność`, title_native: `Деньги и оплата`, focus: `Dzisiaj uczysz się płacić gotówką lub kartą, pytać o cenę i rozumieć podstawowe słowa przy kasie. Przyda się w sklepie, muzeum, kawiarni i metrze.`, vocab: [{ru: `деньги`, pl: `pieniądze`, ipa: `[ˈdien-gi]`},{ru: `рубль`, pl: `rubel`, ipa: `[rubl]`},{ru: `карта`, pl: `karta`, ipa: `[ˈkar-ta]`},{ru: `наличные`, pl: `gotówka`, ipa: `[na-ˈlicz-ny-je]`},{ru: `оплата`, pl: `płatność`, ipa: `[a-ˈpła-ta]`},{ru: `касса`, pl: `kasa`, ipa: `[ˈka-sa]`},{ru: `цена`, pl: `cena`, ipa: `[cie-ˈna]`},{ru: `скидка`, pl: `zniżka`, ipa: `[ˈskit-ka]`},{ru: `чек`, pl: `paragon`, ipa: `[czek]`},{ru: `дорого`, pl: `drogo`, ipa: `[ˈdo-ra-ga]`}], phrases: [{ru: `Можно картой?`, pl: `Czy można kartą?`, ipa: `[ˈmoż-na ˈkar-taj]`},{ru: `Я плачу наличными.`, pl: `Płacę gotówką.`, ipa: `[ja pła-ˈczu na-ˈlicz-ny-mi]`},{ru: `Сколько с меня?`, pl: `Ile płacę?`, ipa: `[ˈskol-ka s mi-ˈnia]`},{ru: `Это дорого.`, pl: `To drogie.`, ipa: `[ˈe-ta ˈdo-ra-ga]`},{ru: `Есть скидка?`, pl: `Czy jest zniżka?`, ipa: `[jest ˈskit-ka]`},{ru: `Чек, пожалуйста.`, pl: `Paragon, proszę.`, ipa: `[czek pa-ˈża-lu-sta]`}], grammar: `Можно to bardzo praktyczne słowo oznaczające „można” albo „czy mogę”. Можно картой? dosłownie znaczy „można kartą?”. To naturalne i szybkie pytanie przy kasie.`, practice: [`Zapytaj, czy można zapłacić kartą.`,`Powiedz, że płacisz gotówką.`,`Zapytaj, ile płacisz.`,`Poproś o paragon.`,`Powiedz, że coś jest drogie.`]},{day: 16, title: `Ubrania i pamiątki`, title_native: `Одежда и сувениры`, focus: `W sklepach z pamiątkami albo ubraniami nauczysz się pytać o rozmiar, kolor i cenę. Dzisiaj ćwiczymy spokojne zakupy bez pośpiechu.`, vocab: [{ru: `одежда`, pl: `ubrania`, ipa: `[a-ˈdież-da]`},{ru: `сувенир`, pl: `pamiątka`, ipa: `[su-vie-ˈnir]`},{ru: `размер`, pl: `rozmiar`, ipa: `[raz-ˈmier]`},{ru: `цвет`, pl: `kolor`, ipa: `[cviet]`},{ru: `красный`, pl: `czerwony`, ipa: `[ˈkras-nyj]`},{ru: `синий`, pl: `niebieski`, ipa: `[ˈsi-nij]`},{ru: `чёрный`, pl: `czarny`, ipa: `[ˈczior-nyj]`},{ru: `белый`, pl: `biały`, ipa: `[ˈbie-łyj]`},{ru: `маленький`, pl: `mały`, ipa: `[ˈma-lień-kij]`},{ru: `большой`, pl: `duży`, ipa: `[bal-ˈszoj]`}], phrases: [{ru: `У вас есть другой размер?`, pl: `Czy macie inny rozmiar?`, ipa: `[u was jest dru-ˈgoj raz-ˈmier]`},{ru: `Мне нужен маленький размер.`, pl: `Potrzebuję małego rozmiaru.`, ipa: `[mnie ˈnu-żen ˈma-lień-kij raz-ˈmier]`},{ru: `Мне нравится этот цвет.`, pl: `Podoba mi się ten kolor.`, ipa: `[mnie ˈnra-vit-sa ˈe-tat cviet]`},{ru: `Сколько стоит этот сувенир?`, pl: `Ile kosztuje ta pamiątka?`, ipa: `[ˈskol-ka ˈsto-it ˈe-tat su-vie-ˈnir]`},{ru: `Можно посмотреть?`, pl: `Czy mogę zobaczyć?`, ipa: `[ˈmoż-na pa-sma-ˈtriet]`},{ru: `Я только смотрю.`, pl: `Tylko oglądam.`, ipa: `[ja ˈtol-ka sma-ˈtriu]`}], grammar: `Этот oznacza „ten” dla rzeczowników męskich, np. этот цвет, этот сувенир. W sklepie bardzo przydaje się Я только смотрю, gdy sprzedawca podchodzi, a ty chcesz tylko obejrzeć rzeczy. To uprzejme i naturalne.`, practice: [`Zapytaj o inny rozmiar.`,`Powiedz, że podoba ci się kolor.`,`Zapytaj o cenę pamiątki.`,`Powiedz, że tylko oglądasz.`,`Wymień po rosyjsku trzy kolory.`]},{day: 17, title: `Muzea, bilety i zwiedzanie`, title_native: `Музеи, билеты и экскурсии`, focus: `Dzisiaj uczysz się kupować bilety do muzeum, pytać o godziny otwarcia i audioprzewodnik. Przyda się w Ermitażu, Galerii Tretiakowskiej albo muzeach regionalnych.`, vocab: [{ru: `музей`, pl: `muzeum`, ipa: `[mu-ˈziej]`},{ru: `билет`, pl: `bilet`, ipa: `[bi-ˈliet]`},{ru: `выставка`, pl: `wystawa`, ipa: `[ˈwy-staf-ka]`},{ru: `экскурсия`, pl: `wycieczka z przewodnikiem`, ipa: `[ek-skur-ˈsi-ja]`},{ru: `гид`, pl: `przewodnik`, ipa: `[git]`},{ru: `аудиогид`, pl: `audioprzewodnik`, ipa: `[au-dio-ˈgit]`},{ru: `открыто`, pl: `otwarte`, ipa: `[at-ˈkry-ta]`},{ru: `закрыто`, pl: `zamknięte`, ipa: `[za-ˈkry-ta]`},{ru: `вход`, pl: `wejście`, ipa: `[fchot]`},{ru: `выход`, pl: `wyjście`, ipa: `[ˈwy-hat]`}], phrases: [{ru: `Два билета, пожалуйста.`, pl: `Dwa bilety, proszę.`, ipa: `[dwa bi-ˈlie-ta pa-ˈża-lu-sta]`},{ru: `Когда музей открыт?`, pl: `Kiedy muzeum jest otwarte?`, ipa: `[kag-ˈda mu-ˈziej at-ˈkryt]`},{ru: `Где вход?`, pl: `Gdzie jest wejście?`, ipa: `[gdie fchot]`},{ru: `Есть аудиогид на польском?`, pl: `Czy jest audioprzewodnik po polsku?`, ipa: `[jest au-dio-ˈgit na ˈpol-skam]`},{ru: `Можно фотографировать?`, pl: `Czy można fotografować?`, ipa: `[ˈmoż-na fa-ta-gra-fi-ˈro-wat]`},{ru: `Во сколько закрывается музей?`, pl: `O której zamyka się muzeum?`, ipa: `[wa ˈskol-ka za-kry-ˈwa-jet-sa mu-ˈziej]`}], grammar: `Можно + bezokolicznik to świetna konstrukcja do pytań o pozwolenie: Можно фотографировать? Można też powiedzieć Можно войти? czyli „czy można wejść?”. W miejscach publicznych ta forma brzmi uprzejmie i neutralnie.`, practice: [`Kup dwa bilety do muzeum.`,`Zapytaj, gdzie jest wejście.`,`Zapytaj, czy można robić zdjęcia.`,`Zapytaj o audioprzewodnik po polsku.`,`Powiedz po rosyjsku „muzeum jest zamknięte”.`]},{day: 18, title: `Pogoda i ubranie na dzień`, title_native: `Погода и одежда на день`, focus: `Dzisiaj uczysz się rozmawiać o pogodzie, co pomoże planować spacer, wycieczkę lub przejazd. W rosyjskojęzycznych krajach pogoda może szybko zmienić plany podróży.`, vocab: [{ru: `погода`, pl: `pogoda`, ipa: `[pa-ˈgo-da]`},{ru: `холодно`, pl: `zimno`, ipa: `[ˈho-ład-na]`},{ru: `тепло`, pl: `ciepło`, ipa: `[tie-ˈpło]`},{ru: `жарко`, pl: `gorąco`, ipa: `[ˈżar-ka]`},{ru: `дождь`, pl: `deszcz`, ipa: `[doszcz]`},{ru: `снег`, pl: `śnieg`, ipa: `[sniek]`},{ru: `ветер`, pl: `wiatr`, ipa: `[ˈwie-tier]`},{ru: `солнце`, pl: `słońce`, ipa: `[ˈson-ce]`},{ru: `облачно`, pl: `pochmurno`, ipa: `[ˈob-łacz-na]`},{ru: `зонт`, pl: `parasol`, ipa: `[zont]`}], phrases: [{ru: `Какая сегодня погода?`, pl: `Jaka jest dziś pogoda?`, ipa: `[ka-ˈka-ja sie-ˈwo-dnia pa-ˈgo-da]`},{ru: `Сегодня холодно.`, pl: `Dzisiaj jest zimno.`, ipa: `[sie-ˈwo-dnia ˈho-ład-na]`},{ru: `Идёт дождь.`, pl: `Pada deszcz.`, ipa: `[i-ˈdiot doszcz]`},{ru: `Мне нужен зонт.`, pl: `Potrzebuję parasola.`, ipa: `[mnie ˈnu-żen zont]`},{ru: `Завтра будет тепло.`, pl: `Jutro będzie ciepło.`, ipa: `[ˈzaw-tra ˈbu-diet tie-ˈpło]`},{ru: `Очень сильный ветер.`, pl: `Bardzo silny wiatr.`, ipa: `[ˈo-czeń ˈsil-nyj ˈwie-tier]`}], grammar: `W rosyjskim o pogodzie często mówi się bezosobowo: холодно, тепло, жарко. Nie trzeba dodawać „jest”. Идёт дождь dosłownie znaczy „idzie deszcz”, ale naturalne tłumaczenie to „pada deszcz”.`, practice: [`Powiedz, że dziś jest zimno.`,`Powiedz, że pada deszcz.`,`Zapytaj o dzisiejszą pogodę.`,`Powiedz, że potrzebujesz parasola.`,`Opisz pogodę w swoim mieście trzema rosyjskimi słowami.`]},{day: 19, title: `Telefon, internet i pomoc techniczna`, title_native: `Телефон, интернет и техническая помощь`, focus: `Podróżnik często potrzebuje Wi-Fi, ładowarki albo karty SIM. Dzisiaj uczysz się pytać o internet, hasło i proste problemy z telefonem.`, vocab: [{ru: `телефон`, pl: `telefon`, ipa: `[tie-lie-ˈfon]`},{ru: `интернет`, pl: `internet`, ipa: `[in-tier-ˈniet]`},{ru: `вай-фай`, pl: `Wi-Fi`, ipa: `[waj-faj]`},{ru: `пароль`, pl: `hasło`, ipa: `[pa-ˈrol]`},{ru: `зарядка`, pl: `ładowarka`, ipa: `[za-ˈriat-ka]`},{ru: `сим-карта`, pl: `karta SIM`, ipa: `[sim-ˈkar-ta]`},{ru: `сеть`, pl: `sieć`, ipa: `[siet]`},{ru: `работает`, pl: `działa`, ipa: `[ra-ˈbo-ta-jet]`},{ru: `не работает`, pl: `nie działa`, ipa: `[nie ra-ˈbo-ta-jet]`},{ru: `помощь`, pl: `pomoc`, ipa: `[ˈpo-maszcz]`}], phrases: [{ru: `У вас есть вай-фай?`, pl: `Czy macie Wi-Fi?`, ipa: `[u was jest waj-faj]`},{ru: `Какой пароль?`, pl: `Jakie jest hasło?`, ipa: `[ka-ˈkoj pa-ˈrol]`},{ru: `Интернет не работает.`, pl: `Internet nie działa.`, ipa: `[in-tier-ˈniet nie ra-ˈbo-ta-jet]`},{ru: `Мне нужна зарядка.`, pl: `Potrzebuję ładowarki.`, ipa: `[mnie ˈnuż-na za-ˈriat-ka]`},{ru: `Где купить сим-карту?`, pl: `Gdzie kupić kartę SIM?`, ipa: `[gdie ku-ˈpit sim-ˈkar-tu]`},{ru: `Можете помочь?`, pl: `Czy może pan/pani pomóc?`, ipa: `[ˈmo-że-tie pa-ˈmocz]`}], grammar: `Работает oznacza „działa” i przydaje się nie tylko przy telefonie. Можно сказать: карта не работает, интернет не работает, билет не работает. To prosty sposób opisania problemu bez zaawansowanej gramatyki.`, practice: [`Zapytaj o Wi-Fi w kawiarni.`,`Zapytaj o hasło.`,`Powiedz, że internet nie działa.`,`Poproś o pomoc.`,`Zapytaj, gdzie kupić kartę SIM.`]},{day: 20, title: `Zdrowie i apteka`, title_native: `Здоровье и аптека`, focus: `Dzisiaj ćwiczysz sytuacje w aptece: ból głowy, przeziębienie, leki i prośba o pomoc. To ważny zestaw na nieoczekiwane problemy w podróży.`, vocab: [{ru: `аптека`, pl: `apteka`, ipa: `[ap-ˈtie-ka]`},{ru: `лекарство`, pl: `lekarstwo`, ipa: `[lie-ˈkar-stwa]`},{ru: `врач`, pl: `lekarz`, ipa: `[wracz]`},{ru: `боль`, pl: `ból`, ipa: `[bol]`},{ru: `голова`, pl: `głowa`, ipa: `[ga-la-ˈwa]`},{ru: `живот`, pl: `brzuch`, ipa: `[żi-ˈwot]`},{ru: `горло`, pl: `gardło`, ipa: `[ˈgor-ła]`},{ru: `температура`, pl: `temperatura`, ipa: `[tiem-pie-ra-ˈtu-ra]`},{ru: `простуда`, pl: `przeziębienie`, ipa: `[pra-ˈstu-da]`},{ru: `помогите`, pl: `proszę pomóc`, ipa: `[pa-ma-ˈgi-tie]`}], phrases: [{ru: `Где аптека?`, pl: `Gdzie jest apteka?`, ipa: `[gdie ap-ˈtie-ka]`},{ru: `У меня болит голова.`, pl: `Boli mnie głowa.`, ipa: `[u mi-ˈnia ba-ˈlit ga-la-ˈwa]`},{ru: `У меня болит живот.`, pl: `Boli mnie brzuch.`, ipa: `[u mi-ˈnia ba-ˈlit żi-ˈwot]`},{ru: `Мне нужно лекарство.`, pl: `Potrzebuję lekarstwa.`, ipa: `[mnie ˈnuż-na lie-ˈkar-stwa]`},{ru: `У меня температура.`, pl: `Mam temperaturę.`, ipa: `[u mi-ˈnia tiem-pie-ra-ˈtu-ra]`},{ru: `Вызовите врача, пожалуйста.`, pl: `Proszę wezwać lekarza.`, ipa: `[ˈwy-za-vi-tie wra-ˈcza pa-ˈża-lu-sta]`}], grammar: `У меня болит... oznacza „boli mnie...”. Po tym zwrocie dodajesz część ciała: голова, живот, горло. To jeden z najważniejszych wzorów w sytuacjach zdrowotnych.`, practice: [`Zapytaj, gdzie jest apteka.`,`Powiedz, że boli cię głowa.`,`Powiedz, że boli cię brzuch.`,`Powiedz, że potrzebujesz lekarstwa.`,`Poproś o wezwanie lekarza.`]},{day: 21, title: `Nagłe sytuacje i bezpieczeństwo`, title_native: `Экстренные ситуации и безопасность`, focus: `Dzisiaj uczysz się podstawowych zwrotów alarmowych: zgubiłem się, potrzebuję pomocy, gdzie jest policja. To język, którego oby nigdy nie trzeba było użyć, ale warto go znać.`, vocab: [{ru: `помощь`, pl: `pomoc`, ipa: `[ˈpo-maszcz]`},{ru: `полиция`, pl: `policja`, ipa: `[pa-ˈli-cy-ja]`},{ru: `опасно`, pl: `niebezpiecznie`, ipa: `[a-ˈpas-na]`},{ru: `безопасно`, pl: `bezpiecznie`, ipa: `[bie-za-ˈpas-na]`},{ru: `документы`, pl: `dokumenty`, ipa: `[da-ku-ˈmien-ty]`},{ru: `кошелёк`, pl: `portfel`, ipa: `[ka-sza-ˈliok]`},{ru: `потерял`, pl: `zgubiłem`, ipa: `[pa-tie-ˈrial]`},{ru: `потеряла`, pl: `zgubiłam`, ipa: `[pa-tie-ˈria-ła]`},{ru: `украли`, pl: `ukradli`, ipa: `[u-ˈkra-li]`},{ru: `срочно`, pl: `pilnie`, ipa: `[ˈsrocz-na]`}], phrases: [{ru: `Помогите, пожалуйста!`, pl: `Proszę pomóc!`, ipa: `[pa-ma-ˈgi-tie pa-ˈża-lu-sta]`},{ru: `Где полиция?`, pl: `Gdzie jest policja?`, ipa: `[gdie pa-ˈli-cy-ja]`},{ru: `Я потерял документы.`, pl: `Zgubiłem dokumenty.`, ipa: `[ja pa-tie-ˈrial da-ku-ˈmien-ty]`},{ru: `Я потеряла кошелёк.`, pl: `Zgubiłam portfel.`, ipa: `[ja pa-tie-ˈria-ła ka-sza-ˈliok]`},{ru: `У меня украли телефон.`, pl: `Ukradziono mi telefon.`, ipa: `[u mi-ˈnia u-ˈkra-li tie-lie-ˈfon]`},{ru: `Это срочно.`, pl: `To pilne.`, ipa: `[ˈe-ta ˈsrocz-na]`}], grammar: `Formy потерял i потеряла zależą od osoby mówiącej: mężczyzna powie потерял, kobieta потеряла. W praktyce warto zapamiętać swoją wersję. У меня украли... dosłownie znaczy „u mnie ukradli...”, czyli „ukradziono mi...”.`, practice: [`Powiedz „proszę pomóc”.`,`Zapytaj, gdzie jest policja.`,`Powiedz, że zgubiłeś lub zgubiłaś dokumenty.`,`Powiedz, że ukradziono ci telefon.`,`Powiedz po rosyjsku „to pilne”.`]},{day: 22, title: `Rozmowy towarzyskie`, title_native: `Дружеские разговоры`, focus: `Dzisiaj uczysz się prowadzić małą rozmowę z lokalną osobą w kawiarni, pociągu albo na wycieczce. Skupiamy się na prostych pytaniach i uprzejmych odpowiedziach.`, vocab: [{ru: `как`, pl: `jak`, ipa: `[kak]`},{ru: `дела`, pl: `sprawy`, ipa: `[die-ˈła]`},{ru: `хорошо`, pl: `dobrze`, ipa: `[ha-ra-ˈszo]`},{ru: `нормально`, pl: `normalnie / w porządku`, ipa: `[nar-ˈmal-na]`},{ru: `интересно`, pl: `ciekawie`, ipa: `[in-tie-ˈries-na]`},{ru: `красиво`, pl: `pięknie`, ipa: `[kra-ˈsi-wa]`},{ru: `город`, pl: `miasto`, ipa: `[ˈgo-rat]`},{ru: `страна`, pl: `kraj`, ipa: `[stra-ˈna]`},{ru: `люблю`, pl: `lubię / kocham`, ipa: `[liu-ˈbliu]`},{ru: `нравится`, pl: `podoba się`, ipa: `[ˈnra-vit-sa]`}], phrases: [{ru: `Как дела?`, pl: `Jak się masz?`, ipa: `[kak die-ˈła]`},{ru: `Хорошо, спасибо.`, pl: `Dobrze, dziękuję.`, ipa: `[ha-ra-ˈszo spa-ˈsi-ba]`},{ru: `Мне нравится этот город.`, pl: `Podoba mi się to miasto.`, ipa: `[mnie ˈnra-vit-sa ˈe-tat ˈgo-rat]`},{ru: `Очень красиво.`, pl: `Bardzo pięknie.`, ipa: `[ˈo-czeń kra-ˈsi-wa]`},{ru: `Я люблю путешествовать.`, pl: `Lubię podróżować.`, ipa: `[ja liu-ˈbliu pu-tie-ˈsze-stwa-wat]`},{ru: `Вы здесь живёте?`, pl: `Czy pan/pani tu mieszka?`, ipa: `[wy zdieś ży-ˈwio-tie]`}], grammar: `Мне нравится oznacza „podoba mi się”. To konstrukcja podobna do polskiego, ale dosłownie bliższa „mnie się podoba”. Możesz powiedzieć Мне нравится город, Мне нравится кафе, Мне нравится музыка.`, practice: [`Zapytaj kogoś, jak się ma.`,`Powiedz, że podoba ci się miasto.`,`Powiedz, że jest bardzo pięknie.`,`Powiedz, że lubisz podróżować.`,`Zapytaj formalnie, czy ktoś tu mieszka.`]},{day: 23, title: `Zaproszenia i plany`, title_native: `Приглашения и планы`, focus: `Dzisiaj uczysz się umawiać proste plany: kawa, spacer, muzeum albo kolacja. To przydatne, gdy poznasz kogoś lokalnego lub podróżujesz z grupą.`, vocab: [{ru: `план`, pl: `plan`, ipa: `[płan]`},{ru: `встреча`, pl: `spotkanie`, ipa: `[ˈfstrie-cza]`},{ru: `кофе`, pl: `kawa`, ipa: `[ˈko-fie]`},{ru: `ужин`, pl: `kolacja`, ipa: `[ˈu-żyn]`},{ru: `прогулка`, pl: `spacer`, ipa: `[pra-ˈguł-ka]`},{ru: `сегодня`, pl: `dzisiaj`, ipa: `[sie-ˈwo-dnia]`},{ru: `завтра`, pl: `jutro`, ipa: `[ˈzaw-tra]`},{ru: `вечером`, pl: `wieczorem`, ipa: `[ˈvie-czie-ram]`},{ru: `свободен`, pl: `wolny`, ipa: `[swa-ˈbo-dien]`},{ru: `свободна`, pl: `wolna`, ipa: `[swa-ˈbod-na]`}], phrases: [{ru: `У вас есть планы?`, pl: `Czy ma pan/pani plany?`, ipa: `[u was jest pła-ny]`},{ru: `Хочешь кофе?`, pl: `Chcesz kawę?`, ipa: `[ˈho-cziesz ˈko-fie]`},{ru: `Пойдём гулять?`, pl: `Pójdziemy na spacer?`, ipa: `[paj-ˈdiom gu-ˈliat]`},{ru: `Я свободен вечером.`, pl: `Jestem wolny wieczorem.`, ipa: `[ja swa-ˈbo-dien ˈvie-czie-ram]`},{ru: `Я свободна завтра.`, pl: `Jestem wolna jutro.`, ipa: `[ja swa-ˈbod-na ˈzaw-tra]`},{ru: `Давай встретимся в семь.`, pl: `Spotkajmy się o siódmej.`, ipa: `[da-ˈwaj ˈfstrie-tim-sia f siem]`}], grammar: `Хочешь to nieformalne „chcesz”, a хотите to formalne lub mnogie „chcecie / pan chce”. W kontaktach z nowo poznaną osobą możesz najpierw użyć хотите, a gdy atmosfera jest luźna, przejść na хочешь.`, practice: [`Zaproponuj kawę nieformalnie.`,`Zaproponuj spacer.`,`Powiedz, że jesteś wolny lub wolna jutro.`,`Zaproponuj spotkanie o siódmej.`,`Ułóż krótką rozmowę o planach na wieczór.`]},{day: 24, title: `Poczta, adresy i wysyłka`, title_native: `Почта, адреса и отправка`, focus: `Dzisiaj uczysz się wysłać pocztówkę, zapytać o znaczek i podać adres. To dobry zestaw dla podróżników, którzy lubią klasyczne pamiątki.`, vocab: [{ru: `почта`, pl: `poczta`, ipa: `[ˈpocz-ta]`},{ru: `адрес`, pl: `adres`, ipa: `[a-ˈdries]`},{ru: `открытка`, pl: `pocztówka`, ipa: `[at-ˈkryt-ka]`},{ru: `марка`, pl: `znaczek`, ipa: `[ˈmar-ka]`},{ru: `письмо`, pl: `list`, ipa: `[pis-ˈmo]`},{ru: `посылка`, pl: `paczka`, ipa: `[pa-ˈsył-ka]`},{ru: `отправить`, pl: `wysłać`, ipa: `[at-ˈpra-wit]`},{ru: `получить`, pl: `otrzymać`, ipa: `[pa-łu-ˈczit]`},{ru: `страна`, pl: `kraj`, ipa: `[stra-ˈna]`},{ru: `индекс`, pl: `kod pocztowy`, ipa: `[ˈin-dieks]`}], phrases: [{ru: `Где почта?`, pl: `Gdzie jest poczta?`, ipa: `[gdie ˈpocz-ta]`},{ru: `Мне нужна марка.`, pl: `Potrzebuję znaczka.`, ipa: `[mnie ˈnuż-na ˈmar-ka]`},{ru: `Я хочу отправить открытку.`, pl: `Chcę wysłać pocztówkę.`, ipa: `[ja ha-ˈczu at-ˈpra-wit at-ˈkryt-ku]`},{ru: `В Польшу, пожалуйста.`, pl: `Do Polski, proszę.`, ipa: `[f ˈpol-szu pa-ˈża-lu-sta]`},{ru: `Вот адрес.`, pl: `Oto adres.`, ipa: `[wot a-ˈdries]`},{ru: `Сколько стоит отправка?`, pl: `Ile kosztuje wysyłka?`, ipa: `[ˈskol-ka ˈsto-it at-ˈpraf-ka]`}], grammar: `Я хочу + bezokolicznik oznacza „chcę coś zrobić”: Я хочу отправить, Я хочу купить, Я хочу посмотреть. To bardzo produktywny wzór w podróży. Po prostu dodajesz czynność po хочу.`, practice: [`Zapytaj, gdzie jest poczta.`,`Powiedz, że potrzebujesz znaczka.`,`Powiedz, że chcesz wysłać pocztówkę.`,`Powiedz „do Polski, proszę”.`,`Zapytaj o koszt wysyłki.`]},{day: 25, title: `Mieszkanie, pokój i codzienne potrzeby`, title_native: `Жильё, комната и ежедневные нужды`, focus: `Dzisiaj ćwiczysz zgłaszanie prostych problemów w hotelu lub mieszkaniu: brak ręcznika, zimno, hałas, zepsuty internet. To praktyczny język na dłuższy pobyt.`, vocab: [{ru: `комната`, pl: `pokój`, ipa: `[ˈkom-na-ta]`},{ru: `кровать`, pl: `łóżko`, ipa: `[kra-ˈwat]`},{ru: `душ`, pl: `prysznic`, ipa: `[dusz]`},{ru: `полотенце`, pl: `ręcznik`, ipa: `[pa-la-ˈtien-ce]`},{ru: `окно`, pl: `okno`, ipa: `[ak-ˈno]`},{ru: `дверь`, pl: `drzwi`, ipa: `[dvier]`},{ru: `шум`, pl: `hałas`, ipa: `[szum]`},{ru: `холодно`, pl: `zimno`, ipa: `[ˈho-ład-na]`},{ru: `грязно`, pl: `brudno`, ipa: `[ˈgriaz-na]`},{ru: `чисто`, pl: `czysto`, ipa: `[ˈczis-ta]`}], phrases: [{ru: `В комнате холодно.`, pl: `W pokoju jest zimno.`, ipa: `[f ˈkom-na-tie ˈho-ład-na]`},{ru: `Мне нужно полотенце.`, pl: `Potrzebuję ręcznika.`, ipa: `[mnie ˈnuż-na pa-la-ˈtien-ce]`},{ru: `Душ не работает.`, pl: `Prysznic nie działa.`, ipa: `[dusz nie ra-ˈbo-ta-jet]`},{ru: `Интернет не работает.`, pl: `Internet nie działa.`, ipa: `[in-tier-ˈniet nie ra-ˈbo-ta-jet]`},{ru: `Слишком шумно.`, pl: `Jest zbyt głośno.`, ipa: `[ˈslisz-kam ˈszum-na]`},{ru: `Можно другую комнату?`, pl: `Czy można inny pokój?`, ipa: `[ˈmoż-na dru-ˈgu-ju ˈkom-na-tu]`}], grammar: `Слишком oznacza „zbyt” i łączy się z przysłówkami: слишком шумно, слишком холодно, слишком дорого. To przydatne, gdy chcesz uprzejmie zgłosić problem bez długiego tłumaczenia.`, practice: [`Powiedz, że w pokoju jest zimno.`,`Powiedz, że prysznic nie działa.`,`Poproś o ręcznik.`,`Powiedz, że jest zbyt głośno.`,`Zapytaj, czy można dostać inny pokój.`]},{day: 26, title: `Na dworcu kolejowym`, title_native: `На вокзале`, focus: `Kolej jest ważnym środkiem transportu w wielu rosyjskojęzycznych regionach. Dzisiaj uczysz się pytać o peron, pociąg, opóźnienie i miejsce.`, vocab: [{ru: `вокзал`, pl: `dworzec`, ipa: `[vag-ˈzał]`},{ru: `поезд`, pl: `pociąg`, ipa: `[ˈpo-jizd]`},{ru: `платформа`, pl: `peron`, ipa: `[płat-ˈfor-ma]`},{ru: `вагон`, pl: `wagon`, ipa: `[wa-ˈgon]`},{ru: `место`, pl: `miejsce`, ipa: `[ˈmie-sta]`},{ru: `билет`, pl: `bilet`, ipa: `[bi-ˈliet]`},{ru: `расписание`, pl: `rozkład jazdy`, ipa: `[ra-spi-ˈsa-ni-je]`},{ru: `опоздание`, pl: `opóźnienie`, ipa: `[a-paz-ˈda-ni-je]`},{ru: `касса`, pl: `kasa`, ipa: `[ˈka-sa]`},{ru: `прибытие`, pl: `przyjazd`, ipa: `[pri-ˈby-ti-je]`}], phrases: [{ru: `Где платформа номер три?`, pl: `Gdzie jest peron numer trzy?`, ipa: `[gdie płat-ˈfor-ma ˈno-mier tri]`},{ru: `Когда прибывает поезд?`, pl: `Kiedy przyjeżdża pociąg?`, ipa: `[kag-ˈda pri-by-ˈwa-jet ˈpo-jizd]`},{ru: `Поезд опаздывает?`, pl: `Czy pociąg jest opóźniony?`, ipa: `[ˈpo-jizd a-ˈpaz-dy-wa-jet]`},{ru: `Это мой вагон?`, pl: `Czy to mój wagon?`, ipa: `[ˈe-ta moj wa-ˈgon]`},{ru: `Где моё место?`, pl: `Gdzie jest moje miejsce?`, ipa: `[gdie ma-ˈjo ˈmie-sta]`},{ru: `Можно купить билет здесь?`, pl: `Czy można kupić bilet tutaj?`, ipa: `[ˈmoż-na ku-ˈpit bi-ˈliet zdieś]`}], grammar: `Мой, моя, моё znaczą „mój/moja/moje” i zależą od rodzaju rzeczownika. Мой вагон, моя карта, моё место. W podróży kolejowej szczególnie przydatne są мой вагон i моё место.`, practice: [`Zapytaj o peron numer trzy.`,`Zapytaj, czy pociąg jest opóźniony.`,`Zapytaj, czy to twój wagon.`,`Zapytaj, gdzie jest twoje miejsce.`,`Kup bilet na dworcu po rosyjsku.`]},{day: 27, title: `Granice, dokumenty i formalności`, title_native: `Граница, документы и формальности`, focus: `Dzisiaj ćwiczysz spokojne odpowiedzi przy kontroli dokumentów, w hotelu lub podczas formalnej rejestracji. Skupiamy się na jasnych zdaniach i bezpiecznych informacjach.`, vocab: [{ru: `граница`, pl: `granica`, ipa: `[gra-ˈni-ca]`},{ru: `документы`, pl: `dokumenty`, ipa: `[da-ku-ˈmien-ty]`},{ru: `паспорт`, pl: `paszport`, ipa: `[ˈpas-part]`},{ru: `виза`, pl: `wiza`, ipa: `[ˈwi-za]`},{ru: `цель`, pl: `cel`, ipa: `[ciel]`},{ru: `поездка`, pl: `podróż / przejazd`, ipa: `[pa-ˈjest-ka]`},{ru: `туризм`, pl: `turystyka`, ipa: `[tu-ˈrizm]`},{ru: `работа`, pl: `praca`, ipa: `[ra-ˈbo-ta]`},{ru: `адрес`, pl: `adres`, ipa: `[a-ˈdries]`},{ru: `дата`, pl: `data`, ipa: `[ˈda-ta]`}], phrases: [{ru: `Вот мои документы.`, pl: `Oto moje dokumenty.`, ipa: `[wot ma-ˈi da-ku-ˈmien-ty]`},{ru: `Цель поездки — туризм.`, pl: `Cel podróży to turystyka.`, ipa: `[ciel pa-ˈjest-ki tu-ˈrizm]`},{ru: `Я еду на неделю.`, pl: `Jadę na tydzień.`, ipa: `[ja ˈje-du na nie-ˈdie-liu]`},{ru: `Вот адрес отеля.`, pl: `Oto adres hotelu.`, ipa: `[wot a-ˈdries a-ˈtie-la]`},{ru: `У меня есть виза.`, pl: `Mam wizę.`, ipa: `[u mi-ˈnia jest ˈwi-za]`},{ru: `Я из Польши.`, pl: `Jestem z Polski.`, ipa: `[ja iz ˈpol-szy]`}], grammar: `Еду oznacza „jadę” i przydaje się przy mówieniu o podróży: Я еду на неделю. Na + okres czasu może oznaczać „na jaki czas”, np. на неделю, на два дня. W formalnych sytuacjach mów krótko i konkretnie.`, practice: [`Powiedz, że celem podróży jest turystyka.`,`Powiedz, że jedziesz na tydzień.`,`Pokaż dokumenty po rosyjsku.`,`Powiedz, że masz wizę.`,`Podaj adres hotelu prostym zdaniem.`]},{day: 28, title: `Opinie i prośby`, title_native: `Мнения и просьбы`, focus: `Dzisiaj uczysz się mówić, co ci się podoba, czego potrzebujesz i o co chcesz poprosić. Te zwroty pozwalają brzmieć bardziej naturalnie w codziennych rozmowach.`, vocab: [{ru: `мнение`, pl: `opinia`, ipa: `[ˈmnie-ni-je]`},{ru: `хороший`, pl: `dobry`, ipa: `[ha-ˈro-szyj]`},{ru: `плохой`, pl: `zły`, ipa: `[pła-ˈhoj]`},{ru: `лучше`, pl: `lepiej`, ipa: `[ˈlucz-sze]`},{ru: `хуже`, pl: `gorzej`, ipa: `[ˈhu-że]`},{ru: `нравится`, pl: `podoba się`, ipa: `[ˈnra-vit-sa]`},{ru: `хочу`, pl: `chcę`, ipa: `[ha-ˈczu]`},{ru: `нужно`, pl: `trzeba / potrzebne`, ipa: `[ˈnuż-na]`},{ru: `можно`, pl: `można`, ipa: `[ˈmoż-na]`},{ru: `пожалуйста`, pl: `proszę`, ipa: `[pa-ˈża-lu-sta]`}], phrases: [{ru: `Мне это нравится.`, pl: `Podoba mi się to.`, ipa: `[mnie ˈe-ta ˈnra-vit-sa]`},{ru: `Мне это не нравится.`, pl: `Nie podoba mi się to.`, ipa: `[mnie ˈe-ta nie ˈnra-vit-sa]`},{ru: `Можно быстрее?`, pl: `Czy można szybciej?`, ipa: `[ˈmoż-na by-ˈstrie-je]`},{ru: `Можно медленнее?`, pl: `Czy można wolniej?`, ipa: `[ˈmoż-na mied-ˈlien-nie-je]`},{ru: `Я хочу другой вариант.`, pl: `Chcę inną opcję.`, ipa: `[ja ha-ˈczu dru-ˈgoj wa-ri-ˈant]`},{ru: `Так лучше.`, pl: `Tak lepiej.`, ipa: `[tak ˈlucz-sze]`}], grammar: `Мне нравится i мне не нравится tworzą prostą parę: podoba mi się / nie podoba mi się. Можно быстрее? i Можно медленнее? są bardzo przydatne w taksówce, rozmowie, podczas lekcji lub przy obsłudze.`, practice: [`Powiedz, że coś ci się podoba.`,`Powiedz, że coś ci się nie podoba.`,`Poproś, by ktoś mówił wolniej.`,`Powiedz „tak lepiej”.`,`Poproś o inną opcję.`]},{day: 29, title: `Rozumienie i proszenie o powtórzenie`, title_native: `Понимание и просьба повторить`, focus: `Nawet znając podstawy, często trzeba poprosić o powtórzenie albo wolniejsze mówienie. Dzisiaj uczysz się ratunkowych zwrotów komunikacyjnych.`, vocab: [{ru: `понимать`, pl: `rozumieć`, ipa: `[pa-ni-ˈmat]`},{ru: `говорить`, pl: `mówić`, ipa: `[ga-wa-ˈrit]`},{ru: `повторить`, pl: `powtórzyć`, ipa: `[pa-f-ta-ˈrit]`},{ru: `медленно`, pl: `wolno`, ipa: `[ˈmied-lien-na]`},{ru: `быстро`, pl: `szybko`, ipa: `[ˈby-stra]`},{ru: `слово`, pl: `słowo`, ipa: `[ˈsło-wa]`},{ru: `фраза`, pl: `fraza`, ipa: `[ˈfra-za]`},{ru: `русский`, pl: `rosyjski`, ipa: `[ˈrus-kij]`},{ru: `польский`, pl: `polski`, ipa: `[ˈpol-skij]`},{ru: `английский`, pl: `angielski`, ipa: `[an-ˈglij-skij]`}], phrases: [{ru: `Я не понимаю.`, pl: `Nie rozumiem.`, ipa: `[ja nie pa-ni-ˈma-ju]`},{ru: `Повторите, пожалуйста.`, pl: `Proszę powtórzyć.`, ipa: `[pa-f-ta-ˈri-tie pa-ˈża-lu-sta]`},{ru: `Говорите медленнее, пожалуйста.`, pl: `Proszę mówić wolniej.`, ipa: `[ga-wa-ˈri-tie mied-ˈlien-nie-je pa-ˈża-lu-sta]`},{ru: `Как это по-русски?`, pl: `Jak to jest po rosyjsku?`, ipa: `[kak ˈe-ta pa-ˈrus-ski]`},{ru: `Вы говорите по-польски?`, pl: `Czy mówi pan/pani po polsku?`, ipa: `[wy ga-wa-ˈri-tie pa-ˈpol-ski]`},{ru: `Я немного говорю по-русски.`, pl: `Mówię trochę po rosyjsku.`, ipa: `[ja nie-ˈmno-ga ga-wa-ˈriu pa-ˈrus-ski]`}], grammar: `Po-rosyjsku języki z czasownikiem говорить często mają formę по-русски, по-польски, по-английски. To odpowiada polskiemu „po rosyjsku”, „po polsku”, „po angielsku”. Я говорю по-русски oznacza „mówię po rosyjsku”.`, practice: [`Powiedz, że nie rozumiesz.`,`Poproś o powtórzenie.`,`Poproś, by ktoś mówił wolniej.`,`Zapytaj, jak coś powiedzieć po rosyjsku.`,`Powiedz, że mówisz trochę po rosyjsku.`]},{day: 30, title: `Dzień podróżnika: łączenie wszystkiego`, title_native: `День путешественника: всё вместе`, focus: `Ostatni dzień łączy hotel, transport, jedzenie, zakupy, pytania i prośby. Ćwiczysz krótkie rozmowy, które naprawdę mogą wydarzyć się podczas jednego dnia w rosyjskojęzycznym mieście.`, vocab: [{ru: `путешествие`, pl: `podróż`, ipa: `[pu-tie-ˈsze-stwi-je]`},{ru: `день`, pl: `dzień`, ipa: `[dien]`},{ru: `утром`, pl: `rano`, ipa: `[ˈu-tram]`},{ru: `днём`, pl: `w dzień`, ipa: `[dniom]`},{ru: `вечером`, pl: `wieczorem`, ipa: `[ˈvie-czie-ram]`},{ru: `место`, pl: `miejsce`, ipa: `[ˈmie-sta]`},{ru: `план`, pl: `plan`, ipa: `[płan]`},{ru: `вопрос`, pl: `pytanie`, ipa: `[wa-ˈpros]`},{ru: `ответ`, pl: `odpowiedź`, ipa: `[at-ˈwiet]`},{ru: `спасибо`, pl: `dziękuję`, ipa: `[spa-ˈsi-ba]`}], phrases: [{ru: `У меня вопрос.`, pl: `Mam pytanie.`, ipa: `[u mi-ˈnia wa-ˈpros]`},{ru: `Мне нужно в центр.`, pl: `Muszę do centrum.`, ipa: `[mnie ˈnuż-na f centr]`},{ru: `Я хочу купить билет.`, pl: `Chcę kupić bilet.`, ipa: `[ja ha-ˈczu ku-ˈpit bi-ˈliet]`},{ru: `Где хорошее кафе?`, pl: `Gdzie jest dobra kawiarnia?`, ipa: `[gdie ha-ˈro-sze-je ka-ˈfie]`},{ru: `Можно счёт, пожалуйста?`, pl: `Czy można rachunek, proszę?`, ipa: `[ˈmoż-na szczot pa-ˈża-lu-sta]`},{ru: `Спасибо за помощь.`, pl: `Dziękuję za pomoc.`, ipa: `[spa-ˈsi-ba za ˈpo-maszcz]`}], grammar: `Dzisiaj najważniejsze jest łączenie gotowych wzorów. Мне нужно..., Я хочу..., Где..., Можно...? pozwalają załatwić większość spraw w podróży. Nie musisz mówić perfekcyjnie, jeśli mówisz jasno, uprzejmie i spokojnie.`, practice: [`Ułóż rozmowę w hotelu z trzema zdaniami.`,`Ułóż rozmowę w kawiarni z zamówieniem i płatnością.`,`Zapytaj o drogę do centrum.`,`Poproś o bilet i zapytaj o cenę.`,`Opisz swój idealny dzień podróży, używając pięciu rosyjskich zwrotów.`]}];

var CONVERSATIONS_PL_RU = [{id: 1, title: `Zamawianie w kawiarni`, scene: `Jesteś w małej kawiarni w centrum Petersburga. Chcesz zamówić kawę i coś słodkiego na wynos, a barista pyta o szczegóły.`, lines: [{who: `them`, ru: `Здравствуйте, что будете заказывать?`, pl: `Dzień dobry, co będzie pan/pani zamawiać?`},{who: `you`, ru: `Здравствуйте, кофе, пожалуйста.`, pl: `Dzień dobry, kawę proszę.`},{who: `them`, ru: `Вам с молоком или без молока?`, pl: `Z mlekiem czy bez mleka?`},{who: `you`, ru: `С молоком, но без сахара.`, pl: `Z mlekiem, ale bez cukru.`},{who: `them`, ru: `Что-нибудь ещё?`, pl: `Coś jeszcze?`},{who: `you`, ru: `Да, одну булочку, пожалуйста.`, pl: `Tak, jedną bułeczkę proszę.`},{who: `them`, ru: `На месте или с собой?`, pl: `Na miejscu czy na wynos?`},{who: `you`, ru: `С собой, пожалуйста.`, pl: `Na wynos, proszę.`},{who: `them`, ru: `Можно картой?`, pl: `Czy płaci pan/pani kartą?`},{who: `you`, ru: `Да, картой. Сколько стоит?`, pl: `Tak, kartą. Ile kosztuje?`},{who: `them`, ru: `Триста рублей.`, pl: `Trzysta rubli.`},{who: `you`, ru: `Спасибо большое.`, pl: `Bardzo dziękuję.`}]},{id: 2, title: `Zameldowanie w hotelu`, scene: `Przyjeżdżasz wieczorem do hotelu w Moskwie. Masz rezerwację i chcesz dowiedzieć się, gdzie jest pokój oraz czy śniadanie jest wliczone.`, lines: [{who: `them`, ru: `Добрый вечер, чем могу помочь?`, pl: `Dobry wieczór, w czym mogę pomóc?`},{who: `you`, ru: `Добрый вечер, у меня есть бронь.`, pl: `Dobry wieczór, mam rezerwację.`},{who: `them`, ru: `На какую фамилию?`, pl: `Na jakie nazwisko?`},{who: `you`, ru: `На фамилию Ковальский.`, pl: `Na nazwisko Kowalski.`},{who: `them`, ru: `Ваш паспорт, пожалуйста.`, pl: `Poproszę pana/pani paszport.`},{who: `you`, ru: `Вот мой паспорт.`, pl: `Oto mój paszport.`},{who: `them`, ru: `Ваш номер на пятом этаже.`, pl: `Pana/pani pokój jest na piątym piętrze.`},{who: `you`, ru: `Где лифт?`, pl: `Gdzie jest winda?`},{who: `them`, ru: `Лифт справа.`, pl: `Winda jest po prawej.`},{who: `you`, ru: `Завтрак включён?`, pl: `Czy śniadanie jest wliczone?`},{who: `them`, ru: `Да, завтрак с семи до десяти.`, pl: `Tak, śniadanie jest od siódmej do dziesiątej.`},{who: `you`, ru: `Спасибо, до свидания.`, pl: `Dziękuję, do widzenia.`}]},{id: 3, title: `Pytanie o drogę`, scene: `Spacerujesz po centrum Kazania i chcesz dojść do najbliższej stacji metra. Zatrzymujesz przechodnia i prosisz o prostą wskazówkę.`, lines: [{who: `you`, ru: `Извините, пожалуйста.`, pl: `Przepraszam bardzo.`},{who: `them`, ru: `Да, слушаю.`, pl: `Tak, słucham.`},{who: `you`, ru: `Где метро?`, pl: `Gdzie jest metro?`},{who: `them`, ru: `Идите прямо, потом поверните налево.`, pl: `Proszę iść prosto, potem skręcić w lewo.`},{who: `you`, ru: `Это далеко?`, pl: `Czy to daleko?`},{who: `them`, ru: `Нет, примерно пять минут.`, pl: `Nie, około pięciu minut.`},{who: `you`, ru: `Станция слева или справа?`, pl: `Stacja jest po lewej czy po prawej?`},{who: `them`, ru: `Станция будет справа.`, pl: `Stacja będzie po prawej.`},{who: `you`, ru: `Повторите, пожалуйста.`, pl: `Proszę powtórzyć.`},{who: `them`, ru: `Прямо и налево, потом справа.`, pl: `Prosto i w lewo, potem po prawej.`},{who: `you`, ru: `Спасибо за помощь.`, pl: `Dziękuję za pomoc.`},{who: `them`, ru: `Пожалуйста.`, pl: `Proszę bardzo.`}]},{id: 4, title: `Kolacja w restauracji`, scene: `Jesteś w restauracji w Mińsku i chcesz zamówić kolację. Pytasz o rekomendację, wyjaśniasz, że nie jesz mięsa, i prosisz o rachunek.`, lines: [{who: `them`, ru: `Добрый вечер, меню, пожалуйста.`, pl: `Dobry wieczór, oto menu.`},{who: `you`, ru: `Спасибо. Что вы рекомендуете?`, pl: `Dziękuję. Co pan/pani poleca?`},{who: `them`, ru: `Сегодня хороший суп и рыба.`, pl: `Dzisiaj dobra jest zupa i ryba.`},{who: `you`, ru: `Я не ем мясо. Рыба есть?`, pl: `Nie jem mięsa. Czy jest ryba?`},{who: `them`, ru: `Да, рыба с картошкой.`, pl: `Tak, ryba z ziemniakami.`},{who: `you`, ru: `Хорошо, я возьму рыбу.`, pl: `Dobrze, wezmę rybę.`},{who: `them`, ru: `Что будете пить?`, pl: `Co będzie pan/pani pić?`},{who: `you`, ru: `Воду, пожалуйста.`, pl: `Wodę proszę.`},{who: `them`, ru: `Вам понравилось?`, pl: `Czy smakowało?`},{who: `you`, ru: `Да, очень вкусно.`, pl: `Tak, bardzo smaczne.`},{who: `you`, ru: `Счёт, пожалуйста.`, pl: `Rachunek proszę.`},{who: `them`, ru: `Конечно, сейчас принесу.`, pl: `Oczywiście, zaraz przyniosę.`}]},{id: 5, title: `Kupowanie biletu na metro`, scene: `Stoisz przy kasie lub automacie w metrze w dużym mieście. Chcesz kupić bilet, zapytać o kartę i upewnić się, czy potrzebna jest przesiadka.`, lines: [{who: `them`, ru: `Здравствуйте, вам билет?`, pl: `Dzień dobry, bilet dla pana/pani?`},{who: `you`, ru: `Да, один билет, пожалуйста.`, pl: `Tak, jeden bilet proszę.`},{who: `them`, ru: `Куда вы едете?`, pl: `Dokąd pan/pani jedzie?`},{who: `you`, ru: `В центр.`, pl: `Do centrum.`},{who: `them`, ru: `Вам нужна карта метро?`, pl: `Czy potrzebuje pan/pani mapy metra?`},{who: `you`, ru: `Да, мне нужна карта метро.`, pl: `Tak, potrzebuję mapy metra.`},{who: `them`, ru: `Вот карта и билет.`, pl: `Oto mapa i bilet.`},{who: `you`, ru: `Нужна пересадка?`, pl: `Czy potrzebna jest przesiadka?`},{who: `them`, ru: `Да, одна пересадка на следующей станции.`, pl: `Tak, jedna przesiadka na następnej stacji.`},{who: `you`, ru: `Можно оплатить картой?`, pl: `Czy można zapłacić kartą?`},{who: `them`, ru: `Да, конечно.`, pl: `Tak, oczywiście.`},{who: `you`, ru: `Спасибо большое.`, pl: `Bardzo dziękuję.`}]},{id: 6, title: `Zakupy w sklepie z pamiątkami`, scene: `Wchodzisz do sklepu z pamiątkami po zwiedzaniu muzeum. Chcesz obejrzeć magnes, zapytać o cenę i kupić mały prezent.`, lines: [{who: `them`, ru: `Здравствуйте, вам помочь?`, pl: `Dzień dobry, pomóc panu/pani?`},{who: `you`, ru: `Здравствуйте, я только смотрю.`, pl: `Dzień dobry, tylko oglądam.`},{who: `them`, ru: `Конечно, пожалуйста.`, pl: `Oczywiście, proszę bardzo.`},{who: `you`, ru: `Сколько стоит этот сувенир?`, pl: `Ile kosztuje ta pamiątka?`},{who: `them`, ru: `Двести рублей.`, pl: `Dwieście rubli.`},{who: `you`, ru: `Можно посмотреть?`, pl: `Czy mogę zobaczyć?`},{who: `them`, ru: `Да, конечно.`, pl: `Tak, oczywiście.`},{who: `you`, ru: `У вас есть другой цвет?`, pl: `Czy macie inny kolor?`},{who: `them`, ru: `Да, есть синий и белый.`, pl: `Tak, jest niebieski i biały.`},{who: `you`, ru: `Мне нравится синий. Я возьму его.`, pl: `Podoba mi się niebieski. Wezmę go.`},{who: `them`, ru: `Пакет нужен?`, pl: `Czy potrzebna torba?`},{who: `you`, ru: `Нет, спасибо.`, pl: `Nie, dziękuję.`}]},{id: 7, title: `W aptece`, scene: `Budzisz się z bólem głowy podczas podróży i idziesz do apteki. Chcesz wyjaśnić problem prostym językiem i poprosić o lekarstwo.`, lines: [{who: `them`, ru: `Здравствуйте, что у вас?`, pl: `Dzień dobry, co panu/pani dolega?`},{who: `you`, ru: `Здравствуйте, у меня болит голова.`, pl: `Dzień dobry, boli mnie głowa.`},{who: `them`, ru: `У вас есть температура?`, pl: `Czy ma pan/pani temperaturę?`},{who: `you`, ru: `Нет, температуры нет.`, pl: `Nie, nie mam temperatury.`},{who: `them`, ru: `Вам нужно лекарство от боли?`, pl: `Potrzebuje pan/pani lekarstwa przeciwbólowego?`},{who: `you`, ru: `Да, пожалуйста.`, pl: `Tak, proszę.`},{who: `them`, ru: `У вас есть аллергия?`, pl: `Czy ma pan/pani alergię?`},{who: `you`, ru: `Да, у меня аллергия на орехи.`, pl: `Tak, mam alergię na orzechy.`},{who: `them`, ru: `Хорошо, это безопасно.`, pl: `Dobrze, to jest bezpieczne.`},{who: `you`, ru: `Сколько стоит?`, pl: `Ile kosztuje?`},{who: `them`, ru: `Сто пятьдесят рублей.`, pl: `Sto pięćdziesiąt rubli.`},{who: `you`, ru: `Спасибо за помощь.`, pl: `Dziękuję za pomoc.`}]},{id: 8, title: `Mała rozmowa z lokalną osobą`, scene: `Siedzisz w pociągu lub kawiarni i zaczynasz luźną rozmowę z lokalną osobą. Chcesz powiedzieć, skąd jesteś, że podoba ci się miasto i że uczysz się rosyjskiego.`, lines: [{who: `you`, ru: `Здравствуйте, можно спросить?`, pl: `Dzień dobry, czy mogę zapytać?`},{who: `them`, ru: `Да, конечно.`, pl: `Tak, oczywiście.`},{who: `you`, ru: `Вы здесь живёте?`, pl: `Czy pan/pani tu mieszka?`},{who: `them`, ru: `Да, я живу здесь уже давно.`, pl: `Tak, mieszkam tu już długo.`},{who: `you`, ru: `Очень красивый город.`, pl: `Bardzo piękne miasto.`},{who: `them`, ru: `Спасибо. Вы турист?`, pl: `Dziękuję. Jest pan/pani turystą?`},{who: `you`, ru: `Да, я из Польши.`, pl: `Tak, jestem z Polski.`},{who: `them`, ru: `Вы говорите по-русски?`, pl: `Czy mówi pan/pani po rosyjsku?`},{who: `you`, ru: `Я немного говорю по-русски.`, pl: `Mówię trochę po rosyjsku.`},{who: `them`, ru: `Очень хорошо. Как вам поездка?`, pl: `Bardzo dobrze. Jak podoba się podróż?`},{who: `you`, ru: `Мне очень нравится.`, pl: `Bardzo mi się podoba.`},{who: `them`, ru: `Добро пожаловать!`, pl: `Witamy!`}]}];